#include<bits/stdc++.h>
using namespace std;
int n,k,w[25],a[25],ans;
bool is_prime(int n) {
	if (n<2) {
		return false;
	}
	for (int i=2; i*i<=n; i++) {
		if (n%i==0) {
			return false;
		}
	}
	return true;
}
void dfs(int p,int num,int s) {
	if(num==k) {
		if (is_prime(s)) {
			ans++;
		}
		return;
	}
	if(p==n+1) {
		return;
	}
	for(int i=1; i>=0; i--) {
		a[p]=i;
		dfs(p+1,num+i,s+w[p]*i);
	}
}
int main() {
	cin>>n>>k;
	for(int i=1; i<=n; i++) {
		cin>>w[i];
	}
	dfs(1,0,0);
	cout<<ans;
	return 0;
}
